-- =============================================================================
-- Duble Slash — Outreach: import 40 design leaders from Tal's LinkedIn
-- connections (linkedin_profiles.csv). All are in-house leaders at product
-- companies, so contact_type = 'company'. Priority assigned by seniority:
--   P0  = VP / SVP / Head / Director / Principal / Senior Director
--   P1  = Lead / Manager / Group Manager / Team Lead / Team Manager
--   P2  = Senior IC / other
--
-- One existing row (Adi Rozen Benvenisti, id 'adi-rozen-benvenisti') is
-- updated with the richer CSV note; the other 39 rows are new inserts.
--
-- Fully idempotent. Single quotes inside notes are doubled per SQL rules.
-- =============================================================================

on conflict (id) do nothing;

-- Enrich Adi's existing row with the CSV's richer description.
update public.outreach_contacts
  set role = 'Director of Product Design',
      notes = 'Leads 30+ person design org (CX, UX, Research, UI) at Israel''s largest bank. Co-created the ''bit'' payment app from the ground up.'
  where id = 'adi-rozen-benvenisti';
